import google.auth
from google.auth.transport.requests import Request
from googleapiclient.discovery import build


class DataprocCluster:
    def __init__(self, project_id: str = None):
        self.credentials, self.project_id = self.get_access(project_id)

    @staticmethod
    def get_access(project_id: str = None):
        credentials, current_project_id = google.auth.default()
        if not project_id:
            project_id = current_project_id
        credentials.refresh(Request())
        return credentials, project_id

    def get_all_clusters(self):
        service = build('dataproc', 'v1', credentials=self.credentials)
        clusters = service.projects().regions().clusters().list(
            projectId=self.project_id,
            region='europe-west1'
        ).execute()
        return clusters.get('clusters', [])

    def get_latest_image(self, spark_major_version: str = "3.5"):
        spark_image_ver = spark_major_version.replace(".", "")
        compute = build('compute', 'v1', credentials=self.credentials)
        response = compute.images().getFromFamily(
            project='qcp-core-green-1',
            family=f'quantexa-dataproc-{spark_image_ver}'
        ).execute()
        return response['selfLink']

    def get_dataproc_auto_scaling_policy(self, autoscaling_policy_id: str):
        dataproc = build('dataproc', 'v1', credentials=self.credentials)
        response = dataproc.projects().regions().autoscalingPolicies().list(
            parent=f'projects/{self.project_id}/regions/europe-west1'
        ).execute()
        policies = response.get('policies', [])
        for policy in policies:
            if policy.get('id') == autoscaling_policy_id:
                return policy
        return None

