 */
def getIteration() {
    def gradlePropertiesPath = "${WORKSPACE}/gradle.properties"
    def gradlePropertiesContent = readFileContent(gradlePropertiesPath)
    def iteration = ""
    gradlePropertiesContent.split("\n").each { line ->
        if (line.startsWith("iteration=")) {
            iteration = line.replace("iteration=", "").trim()
            return
        }
    }
    
    if (iteration == "") {
        throw new Exception("Iteration not found in gradle.properties")
    }
    return iteration
}

